import { Skeleton } from "@workspace/ui/components/skeleton";
import type { Metadata } from "next";
import { Suspense } from "react";
import * as v from "valibot";
import { ChatLandingContainer } from "@/features/chat/landing/landing.server";

export const metadata: Metadata = {
	title: "お見送りサポートチャットを開始する",
};

const searchSchema = v.object({
	org: v.optional(v.string()),
});

export default function Page({ searchParams }: PageProps<"/chats">) {
	const parsedPromise = searchParams.then((sp) =>
		v.parse(searchSchema, {
			org: typeof sp["org"] === "string" ? sp["org"] : undefined,
		}),
	);

	return (
		<main className="container mx-auto flex flex-col items-center p-4 max-w-2xl">
			<Suspense fallback={<Skeleton className="h-64 w-full mt-8" />}>
				<LandingWrapper parsedPromise={parsedPromise} />
			</Suspense>
		</main>
	);
}

async function LandingWrapper({
	parsedPromise,
}: {
	parsedPromise: Promise<{ org?: string }>;
}) {
	const parsed = await parsedPromise;
	return <ChatLandingContainer org={parsed.org} />;
}

import {
	Card,
	CardContent,
	CardHeader,
	CardTitle,
} from "@workspace/ui/components/card";
import { StartChatButton } from "@/app/(public)/chats/_components/start-chat-button.client";
import { getOrganizationDetail } from "@/features/organization/detail/get-organization-detail";

export async function ChatLandingContainer({
	org,
}: {
	org: string | undefined;
}) {
	const organization = org ? await getOrganizationDetail(org) : null;

	return (
		<Card className="w-full mt-8">
			<CardHeader>
				<CardTitle>お見送りサポートチャットへようこそ</CardTitle>
			</CardHeader>
			<CardContent className="flex flex-col gap-4">
				{organization ? (
					<p className="text-sm">
						<strong>{organization.name}</strong>{" "}
						からのご紹介でこちらにアクセスいただいています。
					</p>
				) : (
					<p className="text-sm text-amber-700">
						紹介組織が指定されていません。直接アクセスからもチャットを開始できますが、紹介情報は記録されません。
					</p>
				)}
				<p className="text-sm text-muted-foreground">
					終活、相続発生時の手続き、相続後の資産活用までを AI
					が一緒に整理します。お気軽にご相談ください。
				</p>
				<StartChatButton
					organizationId={organization?.organizationId ?? null}
				/>
				<p className="text-xs text-muted-foreground">
					発行されるチャット URL から、後日いつでも続きから相談できます (
					最終アクセスから 1 週間後はアクセスが遮断されます)。
				</p>
			</CardContent>
		</Card>
	);
}

